// Generated by AI (UnitTest MCP)
import { describe, expect, it, vi } from "vitest";

import { McpClient } from "./mcpClient";
import { ReadinessController, RuntimeHealth } from "./readinessController";
import { ReadinessViewProvider } from "./readinessViewProvider";

const health = (overrides: Partial<RuntimeHealth> = {}): RuntimeHealth => ({
  memory: "memory connected",
  intent: "intent connected",
  terminal: "terminal capture active",
  git: "Git capture active (1 repository)",
  ...overrides,
});

describe("ReadinessController", () => {
  it("derives coordinating state from authoritative graph, board, and design reads", async () => {
    const memory = fakeClient({ graph_stats: { nodes: 9, active_edges: 11 } }, "mindleak-mcp");
    const intent = fakeClient(
      {
        board: [{ id: "task:one" }],
        design_board: [{ id: "design:one" }],
      },
      "lodestar-mcp"
    );
    const update = vi.fn();
    const controller = new ReadinessController(
      memory,
      intent,
      { update } as unknown as ReadinessViewProvider,
      "vscode-abcd1234",
      () => true,
      health(),
      () => undefined
    );

    const snapshot = await controller.refresh();

    expect(memory.callTool).toHaveBeenCalledWith("graph_stats", {});
    expect(intent.callTool).toHaveBeenCalledWith("board", { include_terminal: false });
    expect(intent.callTool).toHaveBeenCalledWith("design_board", {});
    expect(snapshot.state).toBe("coordinating");
    expect(snapshot.action.command).toBe("mindleak.designView.focus");
    expect(snapshot.memory).toContain("0.1.1+test");
    expect(update).toHaveBeenLastCalledWith(snapshot);
  });

  it("keeps optional sensor failures distinct from a core tool failure", async () => {
    const memory = fakeClient({}, "mindleak-mcp");
    memory.callTool.mockRejectedValueOnce(new Error("graph_stats failed"));
    const intent = fakeClient({ board: [], design_board: [] }, "lodestar-mcp");
    const logs: string[] = [];
    const controller = new ReadinessController(
      memory,
      intent,
      { update: vi.fn() } as unknown as ReadinessViewProvider,
      "vscode",
      () => false,
      health({ terminal: "terminal capture disabled" }),
      (message) => logs.push(message)
    );

    const snapshot = await controller.refresh();

    expect(snapshot.state).toBe("disconnected");
    expect(snapshot.detail).toContain("graph_stats failed");
    expect(snapshot.degradedCapabilities).toEqual(["terminal capture disabled"]);
    expect(logs).toEqual(["readiness memory error: graph_stats failed"]);
  });

  it("re-derives from health callbacks without another MCP read", async () => {
    const memory = fakeClient({ graph_stats: { nodes: 3, active_edges: 2 } }, "mindleak-mcp");
    const intent = fakeClient({ board: [], design_board: [] }, "lodestar-mcp");
    const controller = new ReadinessController(
      memory,
      intent,
      { update: vi.fn() } as unknown as ReadinessViewProvider,
      "vscode",
      () => true,
      health(),
      () => undefined
    );
    await controller.refresh();
    const calls = memory.callTool.mock.calls.length + intent.callTool.mock.calls.length;

    controller.setHealth(health({ git: "Git capture degraded: unavailable" }));

    expect(controller.snapshot().state).toBe("degraded_optional");
    expect(memory.callTool.mock.calls.length + intent.callTool.mock.calls.length).toBe(calls);
  });

  it("accepts graph and task facts already fetched by existing views", () => {
    const memory = fakeClient({}, "mindleak-mcp");
    const intent = fakeClient({}, "lodestar-mcp");
    const controller = new ReadinessController(
      memory,
      intent,
      { update: vi.fn() } as unknown as ReadinessViewProvider,
      "vscode",
      () => true,
      health(),
      () => undefined
    );

    controller.setGraph({ nodes: 4, active_edges: 3 });
    controller.setActionableTasks(2);

    expect(controller.snapshot().state).toBe("coordinating");
    expect(controller.snapshot().graph).toEqual({ nodes: 4, activeEdges: 3 });
    expect(memory.callTool).not.toHaveBeenCalled();
    expect(intent.callTool).not.toHaveBeenCalled();
  });
});

function fakeClient(
  results: Record<string, unknown>,
  name: string
): McpClient & {
  callTool: ReturnType<typeof vi.fn>;
} {
  return {
    isReady: vi.fn(() => true),
    serverIdentity: vi.fn(() => ({ name, version: "0.1.1+test" })),
    callTool: vi.fn(async (tool: string) => results[tool]),
  } as unknown as McpClient & { callTool: ReturnType<typeof vi.fn> };
}
